105: // An implementation of Envoy::ConnectionPool::ActiveClient for HTTP/1.1 and HTTP/2
106: class ActiveClient : public Envoy::ConnectionPool::ActiveClient {
107: public:
108:   ActiveClient(HttpConnPoolImplBase& parent, uint64_t lifetime_stream_limit,
109:                uint64_t effective_concurrent_stream_limit,
110:                uint64_t configured_concurrent_stream_limit,
111:                OptRef<Upstream::Host::CreateConnectionData> opt_data)
112:       : Envoy::ConnectionPool::ActiveClient(parent, lifetime_stream_limit,
113:                                             effective_concurrent_stream_limit,
114:                                             configured_concurrent_stream_limit) {
115:     if (opt_data.has_value()) {
116:       initialize(opt_data.value(), parent);
117:       return;
118:     }
119:     // The static cast makes sure we call the base class host() and not
120:     // HttpConnPoolImplBase::host which is of a different type.
121:     Upstream::Host::CreateConnectionData data =
122:         static_cast<Envoy::ConnectionPool::ConnPoolImplBase*>(&parent)->host()->createConnection(
123:             parent.dispatcher(), parent.socketOptions(), parent.transportSocketOptions());
124:     initialize(data, parent);
125:   }
126: 
127:   void initialize(Upstream::Host::CreateConnectionData& data, HttpConnPoolImplBase& parent) {
128:     real_host_description_ = data.host_description_;
129:     codec_client_ = parent.createCodecClient(data);
130:     codec_client_->addConnectionCallbacks(*this);
131:     Upstream::ClusterTrafficStats& traffic_stats = *parent_.host()->cluster().trafficStats();
132:     codec_client_->setConnectionStats(
133:         {traffic_stats.upstream_cx_rx_bytes_total_, traffic_stats.upstream_cx_rx_bytes_buffered_,
134:          traffic_stats.upstream_cx_tx_bytes_total_, traffic_stats.upstream_cx_tx_bytes_buffered_,
135:          &traffic_stats.bind_errors_, nullptr});
136:   }
137: 
138:   void initializeReadFilters() override { codec_client_->initializeReadFilters(); }
139:   absl::optional<Http::Protocol> protocol() const override { return codec_client_->protocol(); }
140:   void close() override { codec_client_->close(); }
141:   virtual Http::RequestEncoder& newStreamEncoder(Http::ResponseDecoder& response_decoder) PURE;
142:   void onEvent(Network::ConnectionEvent event) override {
143:     parent_.onConnectionEvent(*this, codec_client_->connectionFailureReason(), event);
144:   }
145:   uint32_t numActiveStreams() const override { return codec_client_->numActiveRequests(); }
146:   uint64_t id() const override { return codec_client_->id(); }
147:   HttpConnPoolImplBase& parent() { return *static_cast<HttpConnPoolImplBase*>(&parent_); }
148: 
149:   Http::CodecClientPtr codec_client_;
150: };
